const MAX_STOREFRONT_OPTIMIZER = Number(process.env.AGENT_TODO_MAX_STOREFRONT_OPTIMIZER || 1);
// A storefront-optimizer campaign cycle: read-only diagnose on Max → propose a typed campaign / a
