const STOREFRONT_OPTIMIZER_TIMEOUT_MS = 20 * 60 * 1000;
const MAX_REPAIR = Number(process.env.AGENT_TODO_MAX_REPAIR || 2);
// One repair pass: read-only investigation (the signature + sample + the implicated code) + a
