const REPAIR_TIMEOUT_MS = 15 * 60 * 1000;
const MAX_REGRESSION = Number(process.env.AGENT_TODO_MAX_REGRESSION || 1);
// One regression review: read-only investigation (the regressed spec + its failing checks + what
